import{_ as i,o as a,c as t,ag as d}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Media Processing","description":"Supported formats, derivative generation rules, and video playback strategy in Foldergram.","frontmatter":{"title":"Media Processing","description":"Supported formats, derivative generation rules, and video playback strategy in Foldergram."},"headers":[],"relativePath":"media-processing.md","filePath":"media-processing.md","lastUpdated":1774719654000}'),r={name:"media-processing.md"};function o(l,e,s,n,c,h){return a(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="media-processing" tabindex="-1">Media Processing <a class="header-anchor" href="#media-processing" aria-label="Permalink to &quot;Media Processing&quot;">​</a></h1><p>Foldergram generates derivatives so feed and detail views can stay fast without touching original files on every request. Depending on configuration, those derivatives are either created during scans or lazily on first request and then cached on disk.</p><h2 id="supported-formats" tabindex="-1">Supported formats <a class="header-anchor" href="#supported-formats" aria-label="Permalink to &quot;Supported formats&quot;">​</a></h2><h3 id="images" tabindex="-1">Images <a class="header-anchor" href="#images" aria-label="Permalink to &quot;Images&quot;">​</a></h3><ul><li><code>.jpg</code></li><li><code>.jpeg</code></li><li><code>.png</code></li><li><code>.webp</code></li><li><code>.gif</code></li></ul><h3 id="videos" tabindex="-1">Videos <a class="header-anchor" href="#videos" aria-label="Permalink to &quot;Videos&quot;">​</a></h3><ul><li><code>.mp4</code></li><li><code>.mov</code></li><li><code>.m4v</code></li><li><code>.webm</code></li><li><code>.mkv</code></li></ul><h2 id="output-sizes" tabindex="-1">Output sizes <a class="header-anchor" href="#output-sizes" aria-label="Permalink to &quot;Output sizes&quot;">​</a></h2><p>These values are defined in <code>server/src/utils/image-utils.ts</code>.</p><table tabindex="0"><thead><tr><th>Constant</th><th>Value</th><th>Used for</th></tr></thead><tbody><tr><td><code>THUMBNAIL_SIZE</code></td><td><code>640</code></td><td>Feed cards, folder grids, avatars, and video posters</td></tr><tr><td><code>PREVIEW_MAX_WIDTH</code></td><td><code>1500</code></td><td>Detail-view previews and transcodes</td></tr></tbody></table><h2 id="derivative-timing" tabindex="-1">Derivative timing <a class="header-anchor" href="#derivative-timing" aria-label="Permalink to &quot;Derivative timing&quot;">​</a></h2><p><code>DERIVATIVE_MODE</code> controls when missing derivatives are created:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Behavior</th></tr></thead><tbody><tr><td><code>eager</code></td><td>Scans queue derivative generation during indexing.</td></tr><tr><td><code>lazy</code></td><td>Scans index metadata only. Missing thumbnails and previews are generated when <code>/thumbnails/...</code> or <code>/previews/...</code> is first requested.</td></tr></tbody></table><p>Lazy mode still writes the generated files to the configured derivative directories, so subsequent requests use the cached file on disk.</p><h2 id="derivative-mapping" tabindex="-1">Derivative mapping <a class="header-anchor" href="#derivative-mapping" aria-label="Permalink to &quot;Derivative mapping&quot;">​</a></h2><p>Foldergram mirrors relative source paths into the derivative roots.</p><table tabindex="0"><thead><tr><th>Source media</th><th>Thumbnail output</th><th>Preview output</th></tr></thead><tbody><tr><td>Image</td><td><code>.webp</code></td><td><code>.webp</code></td></tr><tr><td>Video</td><td><code>.webp</code></td><td><code>.mp4</code> or direct original playback</td></tr></tbody></table><p>Examples:</p><table tabindex="0"><thead><tr><th>Source</th><th>Thumbnail</th><th>Preview</th></tr></thead><tbody><tr><td><code>trips/oslo/IMG_0001.jpg</code></td><td><code>trips/oslo/IMG_0001.webp</code></td><td><code>trips/oslo/IMG_0001.webp</code></td></tr><tr><td><code>trips/oslo/clip-01.mov</code></td><td><code>trips/oslo/clip-01.webp</code></td><td><code>trips/oslo/clip-01.mp4</code></td></tr></tbody></table><h2 id="image-derivatives" tabindex="-1">Image derivatives <a class="header-anchor" href="#image-derivatives" aria-label="Permalink to &quot;Image derivatives&quot;">​</a></h2><p>Images are processed with Sharp.</p><h3 id="thumbnail" tabindex="-1">Thumbnail <a class="header-anchor" href="#thumbnail" aria-label="Permalink to &quot;Thumbnail&quot;">​</a></h3><ul><li>auto-rotated</li><li>resized to width <code>640</code> without enlargement</li><li>encoded as WebP with <code>quality: 82</code></li></ul><h3 id="preview" tabindex="-1">Preview <a class="header-anchor" href="#preview" aria-label="Permalink to &quot;Preview&quot;">​</a></h3><ul><li>auto-rotated</li><li>resized to width <code>1500</code> without enlargement</li><li>encoded as WebP with <code>quality: 86</code></li></ul><h2 id="image-detail-source" tabindex="-1">Image detail source <a class="header-anchor" href="#image-detail-source" aria-label="Permalink to &quot;Image detail source&quot;">​</a></h2><p><code>IMAGE_DETAIL_SOURCE</code> affects image detail pages only:</p><table tabindex="0"><thead><tr><th>Value</th><th>Behavior</th></tr></thead><tbody><tr><td><code>preview</code></td><td><code>/image/:id</code> uses the generated preview asset.</td></tr><tr><td><code>original</code></td><td><code>/image/:id</code> uses <code>/api/originals/:id</code> for images.</td></tr></tbody></table><p>This setting does not change feed cards, folder grids, avatars, or any video playback behavior.</p><h2 id="video-metadata" tabindex="-1">Video metadata <a class="header-anchor" href="#video-metadata" aria-label="Permalink to &quot;Video metadata&quot;">​</a></h2><p>Videos are probed with <code>ffprobe</code>.</p><p>Foldergram reads:</p><ul><li>width and height</li><li>duration</li><li>creation timestamps when present</li><li>container and codec details used to decide playback strategy</li></ul><h2 id="video-thumbnail-generation" tabindex="-1">Video thumbnail generation <a class="header-anchor" href="#video-thumbnail-generation" aria-label="Permalink to &quot;Video thumbnail generation&quot;">​</a></h2><p>Video thumbnails are generated with <code>ffmpeg</code>:</p><ul><li><code>thumbnail</code> filter picks a representative frame</li><li>the frame is resized to width <code>640</code></li><li>output is encoded as WebP</li></ul><h2 id="video-preview-generation" tabindex="-1">Video preview generation <a class="header-anchor" href="#video-preview-generation" aria-label="Permalink to &quot;Video preview generation&quot;">​</a></h2><p>When a video needs a derived preview, Foldergram transcodes it with <code>ffmpeg</code> to:</p><ul><li>H.264 video</li><li>AAC audio when audio is present</li><li><code>yuv420p</code></li><li><code>+faststart</code></li><li>landscape-equivalent output up to <code>1280x720</code></li><li>portrait and square output that keeps the short edge at or below <code>720</code></li><li>even-numbered output dimensions for encoder compatibility</li></ul><h2 id="direct-original-video-playback" tabindex="-1">Direct-original video playback <a class="header-anchor" href="#direct-original-video-playback" aria-label="Permalink to &quot;Direct-original video playback&quot;">​</a></h2><p>Foldergram can mark the original video as eligible for direct playback in the detail player when all of these are true:</p><ul><li>the file extension is <code>.mp4</code></li><li>the container is compatible with MP4</li><li>the video codec is H.264</li><li>the pixel format is <code>yuv420p</code></li><li>the audio codec is AAC, or there is no audio track</li></ul><p>When that happens:</p><ul><li><code>playbackStrategy</code> is set to <code>original</code></li><li>generated previews still remain the default playback source</li><li>the detail player can expose an <code>HD</code> switch when the original is compatible and higher resolution than the generated preview</li><li>feed cards and other list surfaces continue to use generated preview media</li></ul><h2 id="gif-handling" tabindex="-1">GIF handling <a class="header-anchor" href="#gif-handling" aria-label="Permalink to &quot;GIF handling&quot;">​</a></h2><p>GIF files are accepted as supported images, but derivatives are generated with <code>animated: false</code>. In practice that means Foldergram treats GIF derivatives as static image outputs, not animated preview pipelines.</p><h2 id="timestamp-sources" tabindex="-1">Timestamp sources <a class="header-anchor" href="#timestamp-sources" aria-label="Permalink to &quot;Timestamp sources&quot;">​</a></h2><p>Foldergram resolves <code>taken_at</code> from the best available source:</p><ul><li>EXIF or embedded media metadata when available</li><li>file modification time or first-seen timing when richer metadata is absent</li></ul><p>Those timestamps influence:</p><ul><li>Recent feed ordering</li><li>Moments eligibility</li><li>Highlights fallback behavior</li></ul><h2 id="thumbnail-only-rebuild" tabindex="-1">Thumbnail-only rebuild <a class="header-anchor" href="#thumbnail-only-rebuild" aria-label="Permalink to &quot;Thumbnail-only rebuild&quot;">​</a></h2><p>The thumbnail rebuild action:</p><ul><li>removes the thumbnail cache directory</li><li>recreates it</li><li>rebuilds thumbnails and video poster images for currently indexed media</li></ul><p>It does not regenerate previews. In lazy mode it acts as a thumbnail and poster prewarm only; preview generation still happens on demand.</p><h2 id="why-derivatives-are-mirrored-by-relative-path" tabindex="-1">Why derivatives are mirrored by relative path <a class="header-anchor" href="#why-derivatives-are-mirrored-by-relative-path" aria-label="Permalink to &quot;Why derivatives are mirrored by relative path&quot;">​</a></h2><p>Mirroring keeps the derivative tree predictable and lets Foldergram:</p><ul><li>resolve public asset URLs without exposing arbitrary filesystem paths</li><li>reuse derivatives across scans when the relative source path still matches</li><li>remove per-folder derivative trees safely during folder deletion</li></ul>',58)])])}const m=i(r,[["render",o]]);export{u as __pageData,m as default};
